/// <reference no-default-lib="true"/>

/**
 * Whether to enable browser compatibility mode.
 *
 * When enabled, the types only allow code that works on both CoHTML and the browser.
 *
 * Possible Values:
 * - `polyfilled_compat`: Enable polyfilled browser compatibility mode,
 * this assumes there are polyfills in place in the browser,
 * so only adjust types for things that can't easily be polyfilled.
 * - `unpolyfilled_compat`: Enable unpolyfilled browser compatibility mode,
 * this assumes there are no polyfills in place in the browser at all,
 * so many types will be marked as optional or have warnings about browser compatibility.
 * - `off`: Disable browser compatibility mode.
 *
 * @todo This is a work in progress.
 *
 * @example
 * ```ts
 * // Sets the value of the browser compat mode option in a module to "polyfilled_compat".
 * declare global {
 *     type __CoHTML_BrowserCompatModeOverride__ = __CoHTML_BrowserCompatModeOption__<"polyfilled_compat">;
 * }
 * ```
 *
 * @example
 * ```ts
 * // Sets the value of the browser compat mode option in a classic script to "polyfilled_compat".
 * type __CoHTML_BrowserCompatModeOverride__ = __CoHTML_BrowserCompatModeOption__<"polyfilled_compat">;
 * ```
 */
type __CoHTML_BrowserCompatMode__ =
    /* @ts-ignore */ (
        (any extends globalThis.__CoHTML_BrowserCompatModeOverride__ ? false : true) extends true ? false
        : // @ts-ignore
        globalThis.__CoHTML_BrowserCompatModeOverride__ extends __CoHTML_BrowserCompatModeOptionType__ ? true
        : false
    ) extends true ?
        // @ts-ignore
        globalThis.__CoHTML_BrowserCompatModeOverride__
    :   __CoHTML_BrowserCompatModeOption__<"off">;

type __CoHTML_BrowserCompatModeOption__<T extends __CoHTML_BrowserCompatModeOptionType__> = T;

type __CoHTML_BrowserCompatModeOptionType__ = "polyfilled_compat" | "unpolyfilled_compat" | "off";

type __CoHTML_BrowserCompatModeOptionFilter__<T extends __CoHTML_BrowserCompatModeOptionFilterType__> =
    T extends __CoHTML_BrowserCompatModeOptionType__ ? T
    : T extends "any_compat" ? Extract<__CoHTML_BrowserCompatModeOptionType__, `${string}_compat`>
    : T extends "any" ? __CoHTML_BrowserCompatModeOptionType__
    : never;

type __CoHTML_BrowserCompatModeOptionFilterType__ = __CoHTML_BrowserCompatModeOptionType__ | "any_compat" | "any";
